import pygame
import random
import sys
from pygame.locals import *

# Constants
SCREEN_WIDTH = 1200
SCREEN_HEIGHT = 800
GRID_SIZE = 30
GRID_WIDTH = 10
GRID_HEIGHT = 20
SIDEBAR_WIDTH = 200
PLAYER_COLORS = [(255, 0, 0), (0, 255, 0), (0, 0, 255)]  # Red, Green, Blue for three players

# Shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[1, 1, 1], [0, 1, 0]],  # T
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]]   # Z
]

class Tetrimino:
    def __init__(self, shape, color):
        self.shape = shape
        self.color = color
        self.x = GRID_WIDTH // 2 - len(shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

    def move(self, dx, dy):
        self.x += dx
        self.y += dy

    def get_rotated(self):
        return [list(row) for row in zip(*self.shape[::-1])]

class Player:
    def __init__(self, id, color):
        self.id = id
        self.color = color
        self.grid = [[0 for _ in range(GRID_WIDTH)] for _ in range(GRID_HEIGHT)]
        self.current_piece = None
        self.next_piece = None
        self.score = 0
        self.game_over = False
        self.spawn_piece()

    def spawn_piece(self):
        if self.next_piece:
            self.current_piece = self.next_piece
        else:
            shape = random.choice(SHAPES)
            self.current_piece = Tetrimino(shape, self.color)
        shape = random.choice(SHAPES)
        self.next_piece = Tetrimino(shape, self.color)
        self.current_piece.x = GRID_WIDTH // 2 - len(self.current_piece.shape[0]) // 2
        self.current_piece.y = 0
        if self.check_collision(0, 0):
            self.game_over = True

    def check_collision(self, dx, dy):
        for y, row in enumerate(self.current_piece.shape):
            for x, cell in enumerate(row):
                if cell:
                    new_x = self.current_piece.x + x + dx
                    new_y = self.current_piece.y + y + dy
                    if (new_x < 0 or new_x >= GRID_WIDTH or 
                        new_y >= GRID_HEIGHT or 
                        (new_y >= 0 and self.grid[new_y][new_x])):
                        return True
        return False

    def merge_piece(self):
        for y, row in enumerate(self.current_piece.shape):
            for x, cell in enumerate(row):
                if cell and self.current_piece.y + y >= 0:
                    self.grid[self.current_piece.y + y][self.current_piece.x + x] = self.color

    def clear_lines(self):
        lines_cleared = 0
        for y in range(GRID_HEIGHT):
            if all(self.grid[y]):
                lines_cleared += 1
                for y2 in range(y, 0, -1):
                    self.grid[y2] = self.grid[y2 - 1][:]
                self.grid[0] = [0] * GRID_WIDTH
        return lines_cleared

    def update(self):
        if not self.game_over:
            if not self.check_collision(0, 1):
                self.current_piece.move(0, 1)
            else:
                self.merge_piece()
                lines_cleared = self.clear_lines()
                self.score += lines_cleared * 100
                self.spawn_piece()

    def draw(self, surface, offset_x, offset_y):
        # Draw grid
        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                if self.grid[y][x]:
                    pygame.draw.rect(surface, self.grid[y][x], 
                                    (offset_x + x * GRID_SIZE, offset_y + y * GRID_SIZE, 
                                     GRID_SIZE, GRID_SIZE))
                    pygame.draw.rect(surface, (255, 255, 255), 
                                    (offset_x + x * GRID_SIZE, offset_y + y * GRID_SIZE, 
                                     GRID_SIZE, GRID_SIZE), 1)

        # Draw current piece
        if self.current_piece and not self.game_over:
            for y, row in enumerate(self.current_piece.shape):
                for x, cell in enumerate(row):
                    if cell:
                        pygame.draw.rect(surface, self.current_piece.color, 
                                        (offset_x + (self.current_piece.x + x) * GRID_SIZE, 
                                         offset_y + (self.current_piece.y + y) * GRID_SIZE, 
                                         GRID_SIZE, GRID_SIZE))
                        pygame.draw.rect(surface, (255, 255, 255), 
                                        (offset_x + (self.current_piece.x + x) * GRID_SIZE, 
                                         offset_y + (self.current_piece.y + y) * GRID_SIZE, 
                                         GRID_SIZE, GRID_SIZE), 1)

        # Draw next piece preview
        if self.next_piece:
            for y, row in enumerate(self.next_piece.shape):
                for x, cell in enumerate(row):
                    if cell:
                        pygame.draw.rect(surface, self.next_piece.color, 
                                        (offset_x + GRID_WIDTH * GRID_SIZE + 20 + x * GRID_SIZE, 
                                         offset_y + 50 + y * GRID_SIZE, 
                                         GRID_SIZE, GRID_SIZE))
                        pygame.draw.rect(surface, (255, 255, 255), 
                                        (offset_x + GRID_WIDTH * GRID_SIZE + 20 + x * GRID_SIZE, 
                                         offset_y + 50 + y * GRID_SIZE, 
                                         GRID_SIZE, GRID_SIZE), 1)

        # Draw score
        font = pygame.font.Font(None, 36)
        score_text = font.render(f"Player {self.id + 1}: {self.score}", True, self.color)
        surface.blit(score_text, (offset_x + GRID_WIDTH * GRID_SIZE + 20, offset_y + 150))

        # Draw game over
        if self.game_over:
            font = pygame.font.Font(None, 48)
            game_over_text = font.render("GAME OVER", True, (255, 255, 255))
            surface.blit(game_over_text, (offset_x + GRID_WIDTH * GRID_SIZE // 2 - 100, 
                                         offset_y + GRID_HEIGHT * GRID_SIZE // 2 - 24))

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("3-Player Tetris")
        self.clock = pygame.time.Clock()
        self.players = [Player(i, PLAYER_COLORS[i]) for i in range(3)]
        self.shared_score = 0
        self.font = pygame.font.Font(None, 36)
        self.fall_time = 0
        self.fall_speed = 0.5  # seconds per cell

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == QUIT:
                pygame.quit()
                sys.exit()

            if event.type == KEYDOWN:
                for i, player in enumerate(self.players):
                    if not player.game_over:
                        if i == 0:  # Player 1 controls
                            if event.key == K_LEFT:
                                if not player.check_collision(-1, 0):
                                    player.current_piece.move(-1, 0)
                            elif event.key == K_RIGHT:
                                if not player.check_collision(1, 0):
                                    player.current_piece.move(1, 0)
                            elif event.key == K_DOWN:
                                if not player.check_collision(0, 1):
                                    player.current_piece.move(0, 1)
                            elif event.key == K_UP:
                                rotated = player.current_piece.get_rotated()
                                old_shape = player.current_piece.shape
                                player.current_piece.shape = rotated
                                if player.check_collision(0, 0):
                                    player.current_piece.shape = old_shape
                                else:
                                    player.current_piece.rotate()
                        elif i == 1:  # Player 2 controls
                            if event.key == K_a:
                                if not player.check_collision(-1, 0):
                                    player.current_piece.move(-1, 0)
                            elif event.key == K_d:
                                if not player.check_collision(1, 0):
                                    player.current_piece.move(1, 0)
                            elif event.key == K_s:
                                if not player.check_collision(0, 1):
                                    player.current_piece.move(0, 1)
                            elif event.key == K_w:
                                rotated = player.current_piece.get_rotated()
                                old_shape = player.current_piece.shape
                                player.current_piece.shape = rotated
                                if player.check_collision(0, 0):
                                    player.current_piece.shape = old_shape
                                else:
                                    player.current_piece.rotate()
                        elif i == 2:  # Player 3 controls
                            if event.key == K_j:
                                if not player.check_collision(-1, 0):
                                    player.current_piece.move(-1, 0)
                            elif event.key == K_l:
                                if not player.check_collision(1, 0):
                                    player.current_piece.move(1, 0)
                            elif event.key == K_k:
                                if not player.check_collision(0, 1):
                                    player.current_piece.move(0, 1)
                            elif event.key == K_i:
                                rotated = player.current_piece.get_rotated()
                                old_shape = player.current_piece.shape
                                player.current_piece.shape = rotated
                                if player.check_collision(0, 0):
                                    player.current_piece.shape = old_shape
                                else:
                                    player.current_piece.rotate()

    def update(self):
        current_time = pygame.time.get_ticks() / 1000
        if current_time - self.fall_time > self.fall_speed:
            self.fall_time = current_time
            for player in self.players:
                player.update()

        # Update shared score (average of all players)
        total = sum(p.score for p in self.players)
        self.shared_score = total // len(self.players)

    def draw(self):
        self.screen.fill((0, 0, 0))

        # Draw player boards
        for i, player in enumerate(self.players):
            offset_x = 50 + i * (GRID_WIDTH * GRID_SIZE + SIDEBAR_WIDTH)
            offset_y = 50
            player.draw(self.screen, offset_x, offset_y)

        # Draw shared score
        shared_text = self.font.render(f"Shared Score: {self.shared_score}", True, (255, 255, 255))
        self.screen.blit(shared_text, (SCREEN_WIDTH // 2 - 100, 20))

        pygame.display.flip()

    def run(self):
        while True:
            self.handle_events()
            self.update()
            self.draw()
            self.clock.tick(60)

if __name__ == "__main__":
    game = TetrisGame()
    game.run()

