class Tetromino:
    def __init__(self, x, y, shape_idx):
        self.x = x
        self.y = y
        self.shape = SHAPES[shape_idx]
        self.color = COLORS[shape_idx]
        self.rotation = 0

    def rotate(self):
        self.rotation = (self.rotation + 1) % 4
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

    def get_rotated(self):
        rotated = [list(row) for row in zip(*self.shape[::-1])]
        return rotated

class Player:
    def __init__(self, x_offset):
        self.grid = [[0 for _ in range(GRID_WIDTH)] for _ in range(GRID_HEIGHT)]
        self.current_piece = None
        self.next_piece = None
        self.x_offset = x_offset
        self.score = 0
        self.lines_cleared = 0
        self.game_over = False
        self.spawn_piece()
        self.spawn_next_piece()

    def spawn_piece(self):
        if self.next_piece:
            self.current_piece = self.next_piece
            self.current_piece.x = GRID_WIDTH // 2 - len(self.current_piece.shape[0]) // 2
            self.current_piece.y = 0
        else:
            shape_idx = random.randint(0, len(SHAPES) - 1)
            self.current_piece = Tetromino(GRID_WIDTH // 2 - len(SHAPES[shape_idx][0]) // 2, 0, shape_idx)
        self.spawn_next_piece()

    def spawn_next_piece(self):
        shape_idx = random.randint(0, len(SHAPES) - 1)
        self.next_piece = Tetromino(0, 0, shape_idx)

    def valid_move(self, piece, x_offset=0, y_offset=0):
        for y, row in enumerate(piece.shape):
            for x, cell in enumerate(row):
                if cell:
                    new_x = piece.x + x + x_offset
                    new_y = piece.y + y + y_offset
                    if (new_x < 0 or new_x >= GRID_WIDTH or 
                        new_y >= GRID_HEIGHT or 
                        (new_y >= 0 and self.grid[new_y][new_x])):
                        return False
        return True

    def lock_piece(self):
        for y, row in enumerate(self.current_piece.shape):
            for x, cell in enumerate(row):
                if cell:
                    if self.current_piece.y + y < 0:
                        self.game_over = True
                        return
                    self.grid[self.current_piece.y + y][self.current_piece.x + x] = self.current_piece.color

        cleared_lines = 0
        for y in range(GRID_HEIGHT):
            if all(self.grid[y]):
                cleared_lines += 1
                for y2 in range(y, 0, -1):
                    self.grid[y2] = self.grid[y2 - 1][:]
                self.grid[0] = [0] * GRID_WIDTH

        if cleared_lines > 0:
            self.lines_cleared += cleared_lines
            self.score += cleared_lines * cleared_lines * 100

        self.spawn_piece()

    def move(self, dx, dy):
        if self.valid_move(self.current_piece, x_offset=dx, y_offset=dy):
            self.current_piece.x += dx
            self.current_piece.y += dy
            if dy and not self.valid_move(self.current_piece, y_offset=1):
                self.lock_piece()
            return True
        return False

    def rotate(self):
        rotated_shape = self.current_piece.get_rotated()
        original_shape = self.current_piece.shape
        self.current_piece.shape = rotated_shape
        if not self.valid_move(self.current_piece):
            self.current_piece.shape = original_shape
        else:
            self.current_piece.rotate()

    def drop(self):
        while self.move(0, 1):
            pass

class Game:
    def __init__(self):
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Collaborative Tetris")
        self.clock = pygame.time.Clock()
        self.font = pygame.font.SysFont('Arial', 24)
        self.big_font = pygame.font.SysFont('Arial', 36)
        self.players = [
            Player(0),
            Player(PLAYER_AREA_WIDTH + SIDEBAR_WIDTH),
            Player(2 * (PLAYER_AREA_WIDTH + SIDEBAR_WIDTH))
        ]
        self.last_drop_time = time.time()
        self.drop_interval = 0.5
        self.total_score = 0
        self.shared_lines = 0
        self.game_active = True

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == QUIT:
                return False
            elif event.type == KEYDOWN:
                if event.key == K_ESCAPE:
                    return False
                elif self.game_active:
                    for i, player in enumerate(self.players):
                        if not player.game_over:
                            if i == 0:  # Player 1 controls
                                if event.key == K_a:
                                    player.move(-1, 0)
                                elif event.key == K_d:
                                    player.move(1, 0)
                                elif event.key == K_s:
                                    player.move(0, 1)
                                elif event.key == K_w:
                                    player.rotate()
                                elif event.key == K_SPACE:
                                    player.drop()
                            elif i == 1:  # Player 2 controls
                                if event.key == K_LEFT:
                                    player.move(-1, 0)
                                elif event.key == K_RIGHT:
                                    player.move(1, 0)
                                elif event.key == K_DOWN:
                                    player.move(0, 1)
                                elif event.key == K_UP:
                                    player.rotate()
                                elif event.key == K_RETURN:
                                    player.drop()
                            elif i == 2:  # Player 3 controls
                                if event.key == K_j:
                                    player.move(-1, 0)
                                elif event.key == K_l:
                                    player.move(1, 0)
                                elif event.key == K_k:
                                    player.move(0, 1)
                                elif event.key == K_i:
                                    player.rotate()
                                elif event.key == K_m:
                                    player.drop()
        return True

    def update(self):
        current_time = time.time()
        if current_time - self.last_drop_time > self.drop_interval:
            self.last_drop_time = current_time
            for player in self.players:
                if not player.game_over:
                    player.move(0, 1)

        # Update total score and check for game over
        self.total_score = sum(p.score for p in self.players)
        self.shared_lines = sum(p.lines_cleared for p in self.players)

        # Check if all players are game over
        if all(p.game_over for p in self.players):
            self.game_active = False

    def draw_grid(self, player):
        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                pygame.draw.rect(
                    self.screen, 
                    GRAY if player.grid[y][x] == 0 else player.grid[y][x], 
                    (player.x_offset + x * GRID_SIZE, y * GRID_SIZE, GRID_SIZE, GRID_SIZE), 
                    0 if player.grid[y][x] else 1
                )

    def draw_current_piece(self, player):
        if player.current_piece and not player.game_over:
            for y, row in enumerate(player.current_piece.shape):
                for x, cell in enumerate(row):
                    if cell:
                        pygame.draw.rect(
                            self.screen,
                            player.current_piece.color,
                            (player.x_offset + (player.current_piece.x + x) * GRID_SIZE,
                             (player.current_piece.y + y) * GRID_SIZE,
                             GRID_SIZE, GRID_SIZE)
                        )

    def draw_next_piece(self, player, x_offset, y_offset):
        if player.next_piece:
            for y, row in enumerate(player.next_piece.shape):
                for x, cell in enumerate(row):
                    if cell:
                        pygame.draw.rect(
                            self.screen,
                            player.next_piece.color,
                            (x_offset + x * GRID_SIZE,
                             y_offset + y * GRID_SIZE,
                             GRID_SIZE, GRID_SIZE)
                        )

    def draw_sidebar(self, player, x_offset):
        # Draw player info
        text = self.font.render(f"Player {self.players.index(player) + 1}", True, WHITE)
        self.screen.blit(text, (x_offset, 20))

        # Draw score
        text = self.font.render(f"Score: {player.score}", True, WHITE)
        self.screen.blit(text, (x_offset, 60))

        # Draw lines cleared
        text = self.font.render(f"Lines: {player.lines_cleared}", True, WHITE)
        self.screen.blit(text, (x_offset, 100))

        # Draw next piece
        text = self.font.render("Next:", True, WHITE)
        self.screen.blit(text, (x_offset, 140))
        self.draw_next_piece(player, x_offset, 180)

        if player.game_over:
            text = self.big_font.render("GAME OVER", True, RED)
            self.screen.blit(text, (x_offset, 300))

    def draw(self):
        self.screen.fill(BLACK)

        # Draw player areas
        for i, player in enumerate(self.players):
            # Draw grid background
            pygame.draw.rect(
                self.screen, 
                (50, 50, 50), 
                (player.x_offset, 0, PLAYER_AREA_WIDTH, GRID_HEIGHT * GRID_SIZE)
            )

            self.draw_grid(player)
            self.draw_current_piece(player)

            # Draw sidebar
            sidebar_x = player.x_offset + PLAYER_AREA_WIDTH if i < 2 else player.x_offset - SIDEBAR_WIDTH
            self.draw_sidebar(player, sidebar_x)

        # Draw shared info
        text = self.big_font.render(f"Total Score: {self.total_score}", True, WHITE)
        self.screen.blit(text, (SCREEN_WIDTH // 2 - text.get_width() // 2, SCREEN_HEIGHT - 50))

        text = self.font.render(f"Shared Lines Cleared: {self.shared_lines}", True, WHITE)
        self.screen.blit(text, (SCREEN_WIDTH // 2 - text.get_width() // 2, SCREEN_HEIGHT - 20))

        if not self.game_active:
            text = self.big_font.render("ALL PLAYERS GAME OVER - PRESS ESC TO QUIT", True, RED)
            self.screen.blit(text, (SCREEN_WIDTH // 2 - text.get_width() // 2, SCREEN_HEIGHT // 2))

        pygame.display.flip()

    def run(self):
        running = True
        while running:
            running = self.handle_events()
            if self.game_active:
                self.update()
            self.draw()
            self.clock.tick(FPS)
        pygame.quit()

if __name__ == "__main__":
    game = Game()
    game.run()
